import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { orderApi } from '../api/client';

const STATUS_COLOR = {
  DELIVERED: '#3B6D11', ON_THE_WAY: '#0D7A6A', ASSIGNED: '#0D7A6A',
  SEARCHING: '#BA7517', PENDING: '#378ADD', CANCELLED: '#A32D2D', FAILED: '#A32D2D',
};
const STATUS_UZ = {
  PENDING:'Kutilmoqda', SEARCHING:'Kuryer qidirilmoqda', ASSIGNED:'Tayinlandi',
  PICKED_UP:'Olib ketildi', ON_THE_WAY:"Yo'lda", DELIVERED:'Yetkazildi',
  CANCELLED:'Bekor qilindi', FAILED:'Muvaffaqiyatsiz',
};

export default function MyOrdersPage() {
  const [orders,  setOrders]  = useState([]);
  const [loading, setLoading] = useState(true);
  const [page,    setPage]    = useState(0);
  const [hasMore, setHasMore] = useState(false);

  useEffect(() => {
    orderApi.getMyOrders(page)
      .then(({ data }) => {
        const p = data.data;
        setOrders((prev) => page === 0 ? p.content : [...prev, ...p.content]);
        setHasMore(!p.last);
      })
      .finally(() => setLoading(false));
  }, [page]);

  if (loading && page === 0) return <div style={{ textAlign:'center', padding:40, color:'#6b8080' }}>Yuklanmoqda...</div>;

  return (
    <div style={{ maxWidth:680, margin:'0 auto', padding:16 }}>
      <h2 style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:20, color:'#1a2e2a', marginBottom:16 }}>
        Buyurtmalarim
      </h2>

      {orders.length === 0 ? (
        <div style={{ textAlign:'center', color:'#6b8080', padding:40 }}>
          <p>Hali buyurtma yo'q</p>
          <Link to="/orders/new" style={{ color:'#0D7A6A', fontWeight:600 }}>Birinchi buyurtma berish â†’</Link>
        </div>
      ) : (
        orders.map((o) => (
          <Link key={o.id} to={`/orders/${o.id}`} style={s.card}>
            <div style={s.left}>
              <div style={s.orderId}>#{o.id?.slice(0,8).toUpperCase()}</div>
              <div style={s.addr}>{o.deliveryAddress?.slice(0,50)}</div>
              <div style={s.meta}>{new Date(o.createdAt).toLocaleDateString('uz-UZ')}</div>
            </div>
            <div style={s.right}>
              <div style={s.fee}>{o.totalFee?.toLocaleString()} so'm</div>
              <span style={{ ...s.badge, background: (STATUS_COLOR[o.status] || '#888') + '20',
                             color: STATUS_COLOR[o.status] || '#888' }}>
                {STATUS_UZ[o.status] || o.status}
              </span>
            </div>
          </Link>
        ))
      )}

      {hasMore && (
        <button style={s.moreBtn} onClick={() => setPage((p) => p + 1)}>
          Ko'proq yuklash
        </button>
      )}
    </div>
  );
}

const s = {
  card:    { display:'flex', justifyContent:'space-between', alignItems:'center',
             background:'#fff', border:'1px solid rgba(13,122,106,0.13)', borderRadius:12,
             padding:'14px 16px', marginBottom:10, textDecoration:'none', color:'inherit' },
  left:    { flex:1, minWidth:0 },
  right:   { textAlign:'right', flexShrink:0 },
  orderId: { fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:14, color:'#1a2e2a' },
  addr:    { fontSize:13, color:'#6b8080', marginTop:2, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' },
  meta:    { fontSize:12, color:'#aaa', marginTop:2 },
  fee:     { fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:15, color:'#0D7A6A' },
  badge:   { display:'inline-block', padding:'3px 10px', borderRadius:20, fontSize:11, fontWeight:700, marginTop:4 },
  moreBtn: { width:'100%', padding:'12px 0', background:'transparent', border:'1px solid rgba(13,122,106,0.2)',
             borderRadius:10, fontSize:14, cursor:'pointer', color:'#0D7A6A', fontWeight:500, marginTop:4 },
};
